import { DOUBLE_PI } from './constant'

export interface IGomokuPiece {
  /**
   * Draw gomoku piece.
   */
  draw(context: CanvasRenderingContext2D, x: number, y: number, radius: number): void
}

export class GomokuPiece implements IGomokuPiece {
  protected readonly strokeStyle: string
  protected readonly fillStyle: string

  constructor(strokeStyle: string, fillStyle: string) {
    this.strokeStyle = strokeStyle
    this.fillStyle = fillStyle
  }

  public draw(context: CanvasRenderingContext2D, x: number, y: number, radius: number): void {
    // eslint-disable-next-line no-param-reassign
    context.strokeStyle = this.strokeStyle
    // eslint-disable-next-line no-param-reassign
    context.fillStyle = this.strokeStyle
    context.beginPath()
    context.arc(x, y, radius, 0, DOUBLE_PI, false)
    context.closePath()
    context.stroke()
    context.fill()
  }
}

export const whiteGomokuPiece: IGomokuPiece = new GomokuPiece('#fff', '#eee')

export const blackGomokuPiece: IGomokuPiece = new GomokuPiece('#000', '#111')
