import type { IGomokuPieceData } from '@kyokuya/react-game-gomoku-core'
import { GomokuPlayerType } from '@kyokuya/react-game-gomoku-core'
import type { IPlayer } from './types'

export class HumanPlayer implements IPlayer {
  public readonly type = GomokuPlayerType.HUMAN
  public async move(
    _GOMOKU_SIZE: number,
    _pieces: ReadonlyArray<IGomokuPieceData>,
    _playerId: number,
    clickedCell?: { r: number; c: number },
  ): Promise<{ r: number; c: number } | null> {
    if (clickedCell == null) return null
    const { r, c } = clickedCell
    return { r, c }
  }
}
