import { css, cx, keyframes } from '@emotion/css'
import { useReactiveRef } from '@guanghechen/react-hooks'
import { GomokuActionType, GomokuContextType } from '@kyokuya/react-game-gomoku-core'
import React from 'react'
import { Gomoku, GomokuPieceType } from '../core/Gomoku'
import { blackGomokuPiece, whiteGomokuPiece } from '../core/GomokuPiece'
import { useMove } from '../hook/useMove'

export interface IGomokuBoardProps {
  /**
   * Gomoku board overlay.
   */
  overlay?: React.ReactNode
  /**
   * CSS class name.
   */
  className?: string
}

export const GameBoard: React.FC<IGomokuBoardProps> = props => {
  const { overlay, className } = props
  const { state, dispatch } = React.useContext(GomokuContextType)
  const { GOMOKU_SIZE, gameStatus, gameTick, attemptTick } = state

  const moveRef = useReactiveRef(useMove())
  const piecesRef = useReactiveRef(state.pieces)
  const canvasRef = React.useRef<HTMLCanvasElement>(null)
  const gomokuRef = React.useRef<Gomoku | null>(null)

  React.useEffect(() => {
    if (canvasRef.current) {
      gomokuRef.current = new Gomoku({
        canvas: canvasRef.current,
        lines: GOMOKU_SIZE,
        pieces: piecesRef.current,
        pieceMap: {
          [GomokuPieceType.WHITE]: whiteGomokuPiece,
          [GomokuPieceType.BLACK]: blackGomokuPiece,
        },
        onClick(r: number, c: number) {
          if (r >= 0 && r < GOMOKU_SIZE && c >= 0 && c < GOMOKU_SIZE) {
            dispatch({ type: GomokuActionType.ACTIVE, payload: { r, c } })
            moveRef.current({ r, c })
          }
        },
      })
    }

    return (): void => {
      gomokuRef.current?.destroy()
      gomokuRef.current = null
    }
  }, [GOMOKU_SIZE, dispatch, moveRef, piecesRef])

  React.useEffect(() => {
    if (canvasRef.current && gomokuRef.current) {
      gomokuRef.current.draw(piecesRef.current)
    }
  }, [gameTick, attemptTick, piecesRef])

  {
    const { r = -1, c = -1 } = state.activatedCell ?? {}
    React.useEffect(() => {
      const gomoku = gomokuRef.current
      if (gomoku) {
        gomoku.updateActivateCell(r, c)
        if (canvasRef.current) gomoku.draw(piecesRef.current)
      }
    }, [gameTick, r, c, piecesRef])
  }

  const classes = useStyles()
  return (
    <div className={cx(classes.container, className)}>
      <div key="overlay" className={classes.overlay} data-status={gameStatus}>
        {overlay}
      </div>
      <canvas ref={canvasRef} />
    </div>
  )
}

// eslint-disable-next-line @typescript-eslint/explicit-function-return-type
const useStyles = () => ({
  container: css`
    position: relative;
    box-sizing: content-box;
    display: inline-block;
    width: 100%;
    height: 100%;
    padding: 0;
    border: 0;
    margin: 0;
    font-family: Consolas, 'Source Code Pro', 'Roboto Mono', monospace, sans-serif;
  `,
  overlay: css`
    z-index: 2;
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    display: none;
    width: 100%;
    height: 100%;
    overflow: hidden;
    background: linear-gradient(
      45deg,
      hsl(30deg 20% 90% / 0.2),
      hsl(210deg 20% 100% / 0.3)
    );

    &[data-status="pending"] {
      display: block;
      backdrop-filter: blur(1px);
    }
    &[data-status="running"] {
      display: none;
    }
    &[data-status="paused"] {
      display: block;
      backdrop-filter: blur(16px);
    }
    &[data-status="finished"] {
      display: block;
      backdrop-filter: blur(4px);
      color: #ff00ff;
      animation: 1s 0s ${animations.finished} ease-in-out;
    }
  `,
})

const animations = {
  finished: keyframes`
    0% {
      transform: translate(0, -100px);
    }
    80% {
      transform: translate(0, 20px);
    }
    90% {
      transform: translate(0, -10px);
    }
    95% {
      transform: translate(0, 2px);
    }
    100% {
      transform: translate(0, 0);
    }
  `,
}
