import { css, cx } from '@emotion/css'
import { useReactiveRef } from '@guanghechen/react-hooks'
import type { IGomokuPlayer } from '@kyokuya/react-game-gomoku-core'
import { GomokuPlayerType } from '@kyokuya/react-game-gomoku-core'
import type { SelectChangeEvent } from '@mui/material'
import { MenuItem, Select, TextField } from '@mui/material'
import React from 'react'

export interface IGameSettingsPlayerProps {
  playerId: number
  player: IGomokuPlayer
  disabled: boolean
  itemTitle?: string
  className?: string
  onChanged?(playerId: number, playerType?: GomokuPlayerType, playerName?: string): void
}

export const GameSettingsPlayer: React.FC<IGameSettingsPlayerProps> = props => {
  const { playerId, player, disabled, itemTitle = 'Player', onChanged } = props
  const [playerName, setPlayerName] = React.useState<string>(player.name)
  const playerNameRef = useReactiveRef<string>(playerName)

  const actions = React.useMemo(
    () => ({
      onPlayerNameChange: (e: React.ChangeEvent<HTMLInputElement>): void => {
        setPlayerName(e.target.value)
      },
      onPlayerNameBlur: (): void => {
        const value: string = playerNameRef.current
        onChanged?.(playerId, undefined, value)
      },
      onPlayerTypeChange: (e: SelectChangeEvent<GomokuPlayerType>): void => {
        const value: GomokuPlayerType = e.target.value as GomokuPlayerType
        onChanged?.(playerId, value, undefined)
      },
    }),
    [playerId, onChanged, playerNameRef],
  )

  const classes = useStyles()
  return (
    <div className={cx(classes.container, props.className)}>
      <div className={cx(classes.item, classes.itemLabel)}>
        <span className={classes.label}>{itemTitle}:</span>
        <Select<GomokuPlayerType>
          className={classes.input}
          variant="standard"
          value={player.type}
          disabled={disabled}
          onChange={actions.onPlayerTypeChange}
        >
          <MenuItem value={GomokuPlayerType.HUMAN}>{GomokuPlayerType.HUMAN}</MenuItem>
          <MenuItem value={GomokuPlayerType.COMPUTER}>{GomokuPlayerType.COMPUTER}</MenuItem>
          <MenuItem value={GomokuPlayerType.COMPUTER_STUPID}>
            {GomokuPlayerType.COMPUTER_STUPID}
          </MenuItem>
        </Select>
      </div>
      <div className={classes.item}>
        <span className={classes.label}>Name:</span>
        <TextField
          className={classes.input}
          variant="standard"
          value={playerName}
          disabled={disabled}
          onChange={actions.onPlayerNameChange}
          onBlur={actions.onPlayerNameBlur}
        />
      </div>
    </div>
  )
}

// eslint-disable-next-line @typescript-eslint/explicit-function-return-type
const useStyles = () => ({
  container: css`
    display: flex;
    justify-content: space-between;
  `,
  item: css`
    flex: 1 1 auto;
    display: flex;
    align-items: center;
  `,
  itemLabel: css`
    flex: 0 0 auto;
    min-width: 200px;
  `,
  label: css`
  `,
  input: css`
    && {
      margin-left: 1rem;
    }
  `,
})
